/* adc_osr_config.c - STM32F4 内置过采样器配置 */
#include "stm32f4xx_hal.h"

ADC_HandleTypeDef hadc1;
TIM_HandleTypeDef htim2;

/* 第 1 步：初始化 ADC1 为连续转换 + DMA 循环 */
void adc1_init(void) {
    hadc1.Instance = ADC1;
    hadc1.Init.Resolution = ADC_RESOLUTION12b;
    hadc1.Init.ScanConvMode = ADC_SCAN_DISABLE;
    hadc1.Init.ContinuousConvMode = ENABLE;    // 连续转换
    hadc1.Init.NbrOfConversion = 1;
    hadc1.Init.DiscontinuousConvMode = DISABLE;
    hadc1.Init.ExternalTrigConv = ADC_EXTERNALTRIGCONV_T2_TRGO;
    hadc1.Init.DataAlign = ADC_DATAALIGN_RIGHT;
    hadc1.Init.NbrOfConversion = 1;
    HAL_ADC_Init(&hadc1);

    /* 第 2 步：配置通道 0 (PA0) 采样时间 84 周期 */
    ADC_ChannelConfTypeDef sConfig = {0};
    sConfig.Channel = ADC_CHANNEL_0;
    sConfig.Rank = 1;
    sConfig.SamplingTime = ADC_SAMPLETIME_84CYCLES;
    HAL_ADC_ConfigChannel(&hadc1, &sConfig, 1);

    /* 第 3 步：配置内置过采样器 — 16x 采样, 右移 4 位 */
    __HAL_ADC_OVERRSAMPLING_CONFIG(&hadc1,
        ADC_OVERSAMPLING_RIGHT_SHIFT_4,  // 16 次平均
        ADC_OVERSAMPLING_RATIO_16,       // 过采样率 16
        ADC_OVERSAMPLING_TRIGGERED,      // 定时器触发
        ADC_OVERSAMPLING_MODE_AVERAGE);  // 平均模式
}

/* 第 4 步：配置 TIM2 产生 1kHz TRGO 信号 */
void tim2_trigger_init(void) {
    htim2.Instance = TIM2;
    htim2.Init.Prescaler = 83;           // 84MHz / 84 = 1MHz
    htim2.Init.Period = 999;             // 1MHz / 1000 = 1kHz TRGO
    htim2.Init.ClockDivision = TIM_CLOCKDIVISION_DIV1;
    HAL_TIM_Base_Init(&htim2);

    TIM_MasterConfigTypeDef mConfig = {0};
    mConfig.MasterOutputTrigger = TIM_TRGO_UPDATE;
    mConfig.MasterSlaveMode = TIM_MASTERSLAVEMODE_DISABLE;
    HAL_TIMEx_MasterConfigSynchronization(&htim2, &mConfig);
    HAL_TIM_Base_Start(&htim2);
}

/* 第 5 步：DMA 搬运结果 */
uint32_t adc_osr_result_buf;
void adc1_dma_init(void) {
    HAL_ADCEx_OverSamplingCallback(&hadc1, &adc_osr_result_buf);
    HAL_ADC_Start_DMA(&hadc1, &adc_osr_result_buf, 1);
}

