#include <stdint.h>
#include <assert.h>

#define MAX_SAMPLES 64
#define ADC_MAX_VALUE 4095  /* 12-bit ADC */

/* 安全验证：uint16_t 能容纳 MAX_SAMPLES 次累加吗？ */
static_assert(MAX_SAMPLES * ADC_MAX_VALUE <= 65535,
    "uint16_t overflow risk!");

uint32_t adc_average(const uint16_t *samples, uint8_t count) {
    uint32_t sum = 0;
    for (uint8_t i = 0; i < count; i++) {
        sum += samples[i];  /* uint32_t 不会溢出 */
    }
    return sum >> 4;  /* 除以 16，用位移代替除法 */
}

