/* 电池监测任务——重复的逻辑 */
uint16_t read_battery_voltage(void) {
    uint32_t sum = 0;
    for (int i = 0; i < 16; i++) {
        HAL_ADC_Start(&hadc1);
        HAL_ADC_PollForConversion(&hadc1, 10);
        sum += HAL_ADC_GetValue(&hadc1);
    }
    return sum / 16;
}

/* 温度读取任务——同样的逻辑又写一遍 */
uint16_t read_temperature(void) {
    uint32_t sum = 0;
